import { type IQueryHandler, QueryHandler } from "@nestjs/cqrs";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { PaymentEntity } from "../../payment.entity.ts";
import { PaymentNotFoundException } from "../../exceptions/payment-not-found.exception.ts";
import { GetPaymentQuery } from "./get-payment.query.ts";

@QueryHandler(GetPaymentQuery)
export class GetPaymentHandler
  implements IQueryHandler<GetPaymentQuery, PaymentEntity>
{
  constructor(
    @InjectRepository(PaymentEntity)
    private readonly paymentRepository: Repository<PaymentEntity>,
  ) {}

  async execute(query: GetPaymentQuery): Promise<PaymentEntity> {
    const payment = await this.paymentRepository.findOne({
      where: { id: query.paymentId },
      relations: ["user"],
    });

    if (!payment) {
      throw new PaymentNotFoundException(query.paymentId);
    }

    return payment;
  }
}
